// Извлекаем данные тикета из webhook или manual input
const input = $input.first().json;

// Поддержка разных форматов входных данных
let ticketData = {
  ticket_id: input.case_id || input.ticket_id || input.id || 'manual-test',
  subject: input.subject || '',
  question: input.content || input.first_message_text || input.message || input.body || '',
  channel: input.channel || 'api',
  client_name: input.user_name || input.client_name || 'Unknown',
  created_at: input.created_at || new Date().toISOString()
};

// Очистка HTML если есть
function stripHtml(s) {
  if (!s) return '';
  return String(s)
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<[^>]*>/g, ' ')
    .replace(/&nbsp;/g, ' ')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/\s+/g, ' ')
    .trim();
}

ticketData.question = stripHtml(ticketData.question);
ticketData.subject = stripHtml(ticketData.subject);

// Объединяем subject и question для полного контекста
ticketData.full_question = ticketData.subject 
  ? `${ticketData.subject}\n\n${ticketData.question}`
  : ticketData.question;

return [{ json: ticketData }];

// FAQ база знаний (встроенная для скорости)
// В продакшене можно загружать из Supabase или файла
const FAQ_DATA = {
  "keywords": {
    "сдэк|cdek|сдек": "СД: СДЭК",
    "dalli|далли": "СД: Dalli",
    "5post|5пост|пятерочка": "СД: 5Post",
    "почта.*росси|почтой|ПР": "СД: Почта России",
    "яндекс.*доставк|yandex": "СД: Яндекс Доставка",
    "пэк|pek": "СД: ПЭК",
    "dpd|дпд": "СД: DPD",
    "boxberry|боксберри": "СД: Boxberry",
    "склад|warehouse": "ЛК: Склад",
    "индекс|postal.*code": "ЛК: Склад",
    "магазин|shop|настройк": "ЛК: Настройки магазина",
    "виджет|widget": "Виджет",
    "оффер|offer|тариф": "API: Офферы",
    "создан.*заказ|order.*creat|POST.*order": "API: Создание заказа",
    "статус|status|tracking": "API: Статусы",
    "партия|batch|ф103": "API: Партии",
    "этикетк|label|штрих.*код|barcode": "Документы: Этикетки",
    "накладн|invoice": "Документы: Накладная",
    "возврат|return": "Типы заказов: Возвраты",
    "курьер|courier": "Типы заказов: Курьерские",
    "многомест|places|место": "Типы заказов: Многоместные",
    "наложен.*платеж|cod|payment": "Оплата: НП",
    "ндс|vat": "Оплата: НДС",
    "500|502|503|504|timeout|ошибк.*сервер": "Ошибки: Timeout/5xx",
    "401|403|авториз|unauthorized|токен|token": "API: Авторизация",
    "битрикс|1с|bitrix": "Интеграции: Битрикс"
  },
  "categories": {
    "СД: СДЭК": {
      "typical_answers": [
        "Для выбора ПВЗ СДЭК используйте точный адрес из справочника СДЭК",
        "Редактирование заказа СДЭК: используется PATCH метод, доступно до передачи в СД",
        "Тарифы СДЭК: проверьте настройки тарификатора в ЛК клиента"
      ],
      "escalation_keywords": ["зависш", "не создается", "ошибка сдэк"]
    },
    "СД: Dalli": {
      "typical_answers": [
        "Для Dalli используется PUT метод редактирования (полное обновление)",
        "Интервалы доставки Dalli заполняются автоматически",
        "Многоместные заказы Dalli: укажите places[] с уникальными barcode"
      ],
      "escalation_keywords": ["не работает далли"]
    },
    "ЛК: Склад": {
      "typical_answers": [
        "Индекс подтягивается из сервиса Dadata по введенному адресу",
        "Если индекс не найден - используйте полный адрес с регионом",
        "Для смены склада отгрузки используйте warehouse_id в запросе"
      ],
      "escalation_keywords": ["не могу выбрать склад"]
    },
    "API: Создание заказа": {
      "typical_answers": [
        "Обязательные поля: receiver, deliveryType, places[], payment",
        "Для многоместных заказов: places[].barcode обязателен",
        "deliverySum передается в payment.deliverySum"
      ],
      "escalation_keywords": ["не создается заказ", "ошибка создания"]
    },
    "API: Статусы": {
      "typical_answers": [
        "GET /v2/orders/{id}/details - детальная информация о заказе",
        "Статусы: created, accepted, in_delivery, delivered, returned",
        "Webhook уведомления настраиваются в ЛК в разделе Интеграции"
      ],
      "escalation_keywords": ["статус не обновляется"]
    },
    "Ошибки: Timeout/5xx": {
      "typical_answers": [
        "500/502/503/504 - временные ошибки сервера, повторите запрос через 5-10 секунд",
        "При постоянных 5xx ошибках - сообщите нам для анализа",
        "Timeout - увеличьте таймаут запроса до 30 секунд"
      ],
      "escalation_keywords": ["постоянн", "не работает"]
    },
    "API: Авторизация": {
      "typical_answers": [
        "401 Unauthorized - проверьте токен в заголовке Authorization: Bearer {token}",
        "403 Forbidden - у токена нет доступа к данному ресурсу",
        "Токен можно получить в ЛК -> Настройки -> API"
      ],
      "escalation_keywords": []
    }
  }
};

const ticket = $input.first().json;
const question = (ticket.full_question || '').toLowerCase();

// Поиск категорий по ключевым словам
let matchedCategories = [];
for (const [pattern, category] of Object.entries(FAQ_DATA.keywords)) {
  const regex = new RegExp(pattern, 'i');
  if (regex.test(question)) {
    matchedCategories.push(category);
  }
}

// Убираем дубликаты
matchedCategories = [...new Set(matchedCategories)];

// Собираем релевантные ответы
let relevantFAQ = [];
let needsEscalation = false;

for (const category of matchedCategories) {
  const catData = FAQ_DATA.categories[category];
  if (catData) {
    relevantFAQ.push({
      category: category,
      answers: catData.typical_answers || []
    });

    // Проверяем на эскалацию
    for (const keyword of (catData.escalation_keywords || [])) {
      if (question.includes(keyword)) {
        needsEscalation = true;
      }
    }
  }
}

// Если категории не найдены
if (matchedCategories.length === 0) {
  matchedCategories = ['Общий вопрос'];
  needsEscalation = true;
}

return [{
  json: {
    ...ticket,
    matched_categories: matchedCategories,
    relevant_faq: relevantFAQ,
    needs_escalation: needsEscalation,
    faq_context: relevantFAQ.map(f => 
      `[${f.category}]\n${f.answers.join('\n')}`
    ).join('\n\n')
  }
}];

const data = $input.first().json;

const systemPrompt = `Ты - AI-ассистент службы поддержки MetaShip (агрегатор доставки).

Твоя задача: составить черновик ответа на вопрос клиента для оператора поддержки.

ПРАВИЛА:
1. Отвечай на русском языке
2. Будь вежлив и профессионален
3. Используй информацию из FAQ если она релевантна
4. Если не уверен - НЕ выдумывай, напиши что нужна консультация оператора
5. Структурируй ответ: приветствие, ответ по существу, предложение помощи
6. Не используй markdown разметку (**, ## и т.д.) - только plain text
7. Если вопрос требует доступа к данным клиента (ИНН, GUID заказа) - запроси их

КОНТЕКСТ MetaShip:
- Агрегатор служб доставки (СДЭК, Dalli, 5Post, Почта России, ПЭК, DPD, Boxberry, Яндекс Доставка)
- API для интеграции (REST, JSON-RPC)
- Личный кабинет (ЛК) для ручного создания заказов
- Виджет для сайтов клиентов
- Основные сущности: заказы (orders), офферы (offers), партии (batches), склады (warehouses)`;

const userMessage = `ВОПРОС КЛИЕНТА:
${data.full_question}

ОПРЕДЕЛЕННЫЕ КАТЕГОРИИ: ${data.matched_categories.join(', ')}

РЕЛЕВАНТНАЯ ИНФОРМАЦИЯ ИЗ FAQ:
${data.faq_context || 'Нет релевантной информации'}

${data.needs_escalation ? '⚠️ ВНИМАНИЕ: Вопрос может требовать эскалации на оператора' : ''}

Составь черновик ответа для оператора.`;

return [{
  json: {
    ...data,
    systemPrompt: systemPrompt,
    userMessage: userMessage
  }
}];

const ticketData = $('Search FAQ').first().json;
const aiResponse = $input.first().json;

let draftResponse = aiResponse.message?.content || aiResponse.choices?.[0]?.message?.content || 'Ошибка генерации ответа';

// Формируем сообщение для оператора
const escalationIcon = ticketData.needs_escalation ? '⚠️ ' : '';
const categories = ticketData.matched_categories.join(', ');

const telegramMessage = `${escalationIcon}📩 *Новый тикет #${ticketData.ticket_id}*

👤 Клиент: ${ticketData.client_name}
📂 Категории: ${categories}
📅 ${new Date().toLocaleString('ru-RU')}

❓ *Вопрос:*
${ticketData.full_question.substring(0, 500)}${ticketData.full_question.length > 500 ? '...' : ''}

✍️ *Черновик ответа:*
${draftResponse}

${ticketData.needs_escalation ? '\n⚠️ _Требуется внимание оператора_' : '✅ _Готово к отправке с проверкой_'}`;

return [{
  json: {
    ticket_id: ticketData.ticket_id,
    client_name: ticketData.client_name,
    categories: categories,
    question: ticketData.full_question,
    draft_response: draftResponse,
    needs_escalation: ticketData.needs_escalation,
    telegram_message: telegramMessage,
    generated_at: new Date().toISOString()
  }
}];
